        user, created = User.objects.get_or_create(username=user_info['name_id'])
        if created:
            user.first_name = user_info.get('first_name', '')
            user.last_name = user_info.get('last_name', '')
            user.email = user_info.get('email', '')
            user.save()

        login(request, user)
