def validate_saml_structure(root):
    if root.tag != '{urn:oasis:names:tc:SAML:2.0:protocol}Response':
        return False
    assertion = root.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Assertion')
    if assertion is None:
        return False
    return True

def extract_user_info(root):
    assertion = root.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Assertion')
    if assertion is None:
        return None

    name_id = assertion.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}NameID')
    if name_id is None:
        return None

    attributes = {}
    attribute_statement = assertion.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}AttributeStatement')
    if attribute_statement is not None:
        for attribute in attribute_statement.findall('.//{urn:oasis:names:tc:SAML:2.0:assertion}Attribute'):
            attr_name = attribute.get('Name')
            attr_value = attribute.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}AttributeValue').text
            attributes[attr_name] = attr_value

    return {
        'name_id': name_id.text,
        'first_name': attributes.get('FirstName'),
        'last_name': attributes.get('LastName'),
        'email': attributes.get('Email')
    }